"""
MKT Christ Layer — Ezekiel chapters 6–10
Run: python3 scripts/zc-christ-ezekiel-6-10-fill.py

Every verse must have an entry. Brief entries are acceptable for transitional
verses; substantive entries where Christological content is rich.

Key Christological clusters:
- Ch 6: Judgment on high places — Jesus cleanses the temple, the new high place
  is his body (John 2:19-21); the remnant who escape and remember (Rom 11:5).
- Ch 7: The End Has Come — the Day of the LORD as the day of Christ's judgment
  (Acts 17:31); no buyer rejoicing in what was bought (Matt 6:19-21); the king
  mourning (Rev 6:15-17).
- Ch 8: Temple Corruption Vision — Jesus weeping over Jerusalem (Luke 19:41-44);
  the abomination of desolation (Matt 24:15); women weeping for Tammuz / the
  true mourning for Christ at the cross.
- Ch 9: The tav/mark on the foreheads of the faithful — the seal of the Spirit
  (2 Cor 1:22; Eph 1:13; Rev 7:3; 14:1); judgment beginning with the house of
  God (1 Pet 4:17); Ezekiel's intercession (v.8) anticipating Christ's mediation.
- Ch 10: The coals scattered over the city — purification/judgment fire;
  the four living creatures = Rev 4:7 (lion, ox, human face, eagle); the glory
  departing east = Christ's departure/return pattern.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EZK_CHRIST = {
  "6": {
    "1": "<p>The word-event formula and the command to set the prophetic face toward the mountains of Israel. The mountains as recipients of judgment oracle anticipate the day when Christ the true mountain of Israel will replace the high places with himself — the new mountain to which all nations will stream (Isa 2:2-3; Matt 5:1).</p>",
    "2": "<p>'Son of man, set your face against the mountains of Israel and prophesy against them' — the prophetic confrontation with Israel's illegitimate worship sites. Jesus similarly confronts the established religious sites of his day, overturning the temple tables (John 2:13-17) and predicting the temple's destruction (Matt 24:2). The prophet's face set against the mountains of corruption is the type of the Messiah's face set steadfastly toward Jerusalem (Luke 9:51).</p>",
    "3": "<p>'Your altars will be desolated and your incense altars will be shattered, and I will make your slain fall before your idols' — the destruction of the false worship sites. The desolation of the high places and their altars points to the new worship that Christ introduces: a time when the Father will be worshiped neither on Mount Gerizim nor Jerusalem but in spirit and truth (John 4:21-24). The obliteration of false altars makes way for the one altar that counts — the cross of Christ.</p>",
    "4": "<p>The slain thrown before their idols — the irony of idol-worship: those who bowed to images become corpses before them. Paul argues that idol-worship is ultimately self-destructive (1 Cor 10:19-22); what is sacrificed to idols goes to demons, and those who commune with demons share their fate. Christ's triumph over the principalities and powers (Col 2:15) is the eschatological form of this high-place destruction.</p>",
    "5": "<p>'I will lay the corpses of the Israelites before their idols and scatter your bones around your altars' — the defilement of the altars by the bones of the worshipers is deeply ironic. In Christ, the relationship between body and altar is reversed: he gives his body at the altar of the cross, not as a victim of meaningless death but as the willing sacrifice whose blood purifies the altar (Heb 13:10-12).</p>",
    "6": "<p>The comprehensive desolation of the high places and their cult infrastructure. The end of Israel's self-organized worship makes way for the worship that God himself establishes through Christ. The desolate high places of judgment anticipate the eschatological truth that 'the LORD alone will be exalted in that day' (Isa 2:17).</p>",
    "7": "<p>'The slain will fall in your midst, and you will know that I am the LORD' — recognition through judgment. The pattern recurs throughout Ezekiel: judgment produces the knowledge of YHWH that devotion to idols prevented. The cross of Christ is the ultimate instance of this pattern: the judgment that fell on the Son produces the knowledge of the Father's love that all other religion failed to deliver (Rom 5:8).</p>",
    "8": "<p>'But I will spare some of you — some will escape the sword among the nations when you are scattered through the countries' — the remnant promise within the judgment oracle. Paul identifies the eschatological remnant as those chosen by grace: 'So too, at the present time there is a remnant chosen by grace' (Rom 11:5). The survivors scattered among the nations are the type of the Jewish remnant who believe in Jesus and the Gentile believers grafted in through the same grace.</p>",
    "9": "<p>'Then your survivors will remember me among the nations to which they have been exiled — how I was broken by their adulterous hearts' — YHWH's broken heart at Israel's idolatry. The language of divine heartbreak prefigures the NT's insistence that sin is relational betrayal, not merely legal violation. Jesus weeps over Jerusalem (Luke 19:41-44) because the infidelity that broke YHWH's heart in Ezekiel's day culminates in the generation that rejects the Son.</p>",
    "10": "<p>'They will know that I am the LORD; I did not threaten in vain to bring this disaster on them' — YHWH vindicating his word through fulfillment. Jesus uses the same self-vindicating logic: 'I am telling you now before it happens, so that when it does happen you will believe that I am he' (John 13:19). Ezekiel's prophetic authority established through fulfilled judgment anticipates Christ's authority established through his announced death and resurrection.</p>",
    "11": "<p>'Strike your hands together and stamp your foot and cry out in grief over all the evil and detestable practices of the house of Israel' — the embodied grief of the prophet over Israel's sin. Jesus similarly embodies grief over Israel's unbelief (John 11:33-35; Luke 19:41). The prophet who grieves over what he must announce points to the Messiah who weeps over the judgment he must pronounce and bear.</p>",
    "12": "<p>'The one far away will die by plague; the one nearby will fall by the sword; and the one who survives and is spared will die by famine. So I will exhaust my wrath upon them' — the comprehensive judgment from which there is no escape by geography. Only the cross provides a way through YHWH's exhausted wrath: Christ became the one on whom YHWH's wrath was fully spent (Rom 3:25; 1 John 2:2), opening the way for the remnant to survive.</p>",
    "13": "<p>'You will know that I am the LORD when their slain lie among their idols around their altars, on every high hill and mountain top, under every leafy tree and every thick oak' — the green tree motif of illicit worship (cf. Deut 12:2; Jer 2:20; 3:6). Jesus as the new tree planted by YHWH (Isa 11:1; John 15:1-5) replaces every false tree under which Israel had worshiped. The branch of Jesse becomes the tree of life, replacing the trees of idolatry with the one tree that gives life.</p>",
    "14": "<p>'I will stretch out my hand against them and make the land desolate and waste everywhere they live, from the wilderness to Riblah' — the outstretched hand of divine judgment from south (the Negev wilderness) to north (Riblah near Hamath). The geographic comprehensiveness of the judgment is reversed in the geographic comprehensiveness of the gospel: from Jerusalem to the ends of the earth (Acts 1:8). The same hand outstretched in judgment is stretched out in invitation through the gospel (Isa 65:2; Rom 10:21).</p>"
  },
  "7": {
    "1": "<p>The word-event formula opening the 'End Has Come' oracle — one of the most intense judgment poems in the Hebrew Bible. The language of finality and the 'end' points forward to the Day of the LORD in both its historical form (586 BCE) and its ultimate eschatological form in Christ's return.</p>",
    "2": "<p>'The end has come upon the four corners of the land' — the four-corners language is cosmic in scope. The Day of YHWH is not a regional event but a universal reckoning. Christ uses the same four-corners language for his eschatological return: 'he will send his angels with a loud trumpet call, and they will gather his elect from the four winds, from one end of heaven to the other' (Matt 24:31).</p>",
    "3": "<p>'Now the end is upon you, and I will unleash my anger against you and judge you according to your ways and repay you for all your detestable practices' — judgment according to deeds is the consistent biblical standard (Rom 2:6; Rev 20:12-13). Christ stands as the judge on the last day (Acts 17:31; 2 Cor 5:10), and his judgment is precisely the 'according to your ways' standard of Ezekiel's oracle — but he also stands as the one who bore that judgment for those who are in him (2 Cor 5:21).</p>",
    "4": "<p>'My eye will not spare you; I will not have pity. I will repay you for your conduct and for the detestable practices among you. Then you will know that I am the LORD' — the withdrawal of mercy from those who have persistently rejected it. The same divine seriousness about sin that produces the 'no pity' judgment here is what drove the sending of the Son: 'He who did not spare his own Son but gave him up for us all' (Rom 8:32). The logic of 'no sparing' in judgment finds its counterpart in the 'no sparing' of the cross.</p>",
    "5": "<p>'Thus says the Lord GOD: Disaster! An unparalleled disaster — look, it is coming!' — the <em>ra'ah achat ra'ah</em> (one disaster, a unique disaster) approaching. The language of the unique, unprecedented disaster anticipates the 'great tribulation, unequaled from the beginning of the world' of Matt 24:21. Christ himself describes the coming judgment in language drawn from Ezekiel 7; the day of Jerusalem's fall in 70 CE and the eschatological day of Christ's return together constitute the fulfillment of this 'unparalleled disaster' oracle.</p>",
    "6": "<p>'The end has come! The end has come! It has stirred itself against you — look, it is coming!' — the repeated 'end' (<em>qetz</em>) creates urgency. The end is not merely termination but the arrival of a decisive moment. Amos 8:2 uses the same wordplay (qetz/qayitz, end/summer fruit). The eschatological 'end' in Daniel 8:17-19; 12:4,9 echoes Ezekiel's oracle; Christ's description of 'the end' (<em>telos</em>, Matt 24:14; Mark 13:7) uses the same terminal vocabulary.</p>",
    "7": "<p>'The hour of doom is coming upon you who dwell in the land; the time is near — the day of tumult, not joyful shouting on the mountains' — the 'time is near' formula. When Jesus announces 'the time has come' (Mark 1:15; John 12:23; 17:1), he uses the same 'time' (<em>kairos</em>) vocabulary of eschatological arrival. The day of tumult rather than joyful celebration is the inverse of what Israel expected; the Lord's day arrives not as celebration but as reckoning.</p>",
    "8": "<p>'I am about to pour out my wrath on you and spend my anger against you; I will judge you according to your conduct and repay you for all your detestable practices' — the pouring out of divine wrath. At Calvary, God's wrath was 'poured out' on his own Son as the propitiation for sin (Rom 3:25; 1 John 4:10). The cup of wrath that Israel faced in 586 BCE was the cup that Jesus asked might pass from him in Gethsemane (Matt 26:39) — and which he drank on behalf of those who deserved it.</p>",
    "9": "<p>'I will not look on you with pity or spare you; I will repay you in accordance with your conduct and the detestable practices among you. Then you will know that it is I the LORD who strikes you' — the divine identity revealed through judgment: 'I the LORD who strikes you.' At the cross, it was 'the LORD who strikes' (Isa 53:4 — 'we considered him stricken by God, smitten by him') — but what appeared to be the striking of the servant was actually the striking of the substitute who bore the judgment that should have fallen on the sinners.</p>",
    "10": "<p>'Look, the day! See, it comes — the doom has burst forth, the rod has budded, arrogance has blossomed!' — the imagery of budding/blossoming reversed: instead of the righteous branch of Jesse (Isa 11:1), here arrogance (<em>zadon</em>) and the rod of judgment bud and bloom. The flowering of sin reaches its full growth and requires its full harvest. Christ comes to cut down the blossomed rod of arrogance through his own humility — the branch that brings life rather than doom (John 15:1-5).</p>",
    "11": "<p>'Violence has grown into a rod of wickedness. None of them shall remain — none of their multitude, none of their wealth, and nothing eminent among them' — the thorough dissolution of all that seemed permanent and impressive. Jesus describes the same dissolution of apparently permanent structures: 'Not one stone here will be left on another; every one will be thrown down' (Matt 24:2). Human achievements — wealth, numbers, prominence — share the impermanence of the temple stones.</p>",
    "12": "<p>'The time has come; the day has arrived. Let not the buyer rejoice nor the seller mourn, for wrath is upon all their multitude' — the end of economic activity in its ordinary sense. Jesus warns against storing up earthly treasures (Matt 6:19-21) precisely because the day arrives when buyer and seller alike face the same judgment regardless of their transactions. In the eschatological day, commercial categories dissolve into a single question: did you know the Master?</p>",
    "13": "<p>'For the seller will not return to the property he has sold as long as both remain alive, for the vision concerns the whole multitude; it will not be reversed' — the Jubilee provisions (Lev 25) guaranteed land return, but the coming judgment suspends even covenant-legal protections. Christ's teaching on the kingdom (Mark 10:28-30) promises restoration of everything given up for him — but not on the basis of the old land-tenure law. The new inheritance is secured not by covenant-law but by resurrection.</p>",
    "14": "<p>'They have blown the trumpet and made everything ready, but no one goes to battle, for my wrath is upon all their multitude' — the paralysis in the face of divine judgment. Despite military preparation, the army cannot fight. This stands in contrast to the armies of heaven that follow Christ at his return (Rev 19:14) — the only battle that succeeds against the wrath of YHWH is the battle that Christ himself fights as the LORD of hosts (Rev 19:15-16).</p>",
    "15": "<p>'The sword is outside; plague and famine are inside. Whoever is in the country will die by the sword; whoever is in the city — famine and plague will devour him' — no safe location. The promise to those in Christ reverses this: 'neither death nor life... nor anything else in all creation, will be able to separate us from the love of God that is in Christ Jesus our Lord' (Rom 8:38-39). The complete exposure of Ezekiel 7 is answered by the complete security of Romans 8.</p>",
    "16": "<p>'All survivors who escape will be on the mountains, moaning like doves of the valleys, each because of his iniquity' — the survivors moaning, not celebrating. The individual moral accounting ('because of his iniquity') anticipates the personal accountability of the judgment seat (2 Cor 5:10). The moaning dove imagery points forward to the dove at Jesus's baptism — the Spirit descending as a dove marks the one who takes on the iniquity of all, so that survivors need not moan over their own.</p>",
    "17": "<p>'Every hand will be feeble, and every knee will become as weak as water' — universal human weakness before the day of divine judgment. 'Every knee will bow' (Rom 14:11; Phil 2:10) in the NT context, but here as feebleness in terror. The very posture of weakness that judgment produces is, in the NT, the posture of worship before the one who stood strong in the day of judgment on our behalf.</p>",
    "18": "<p>'They will put on sackcloth and be clothed with terror; every face will be covered with shame and every head will be shaved' — the mourning postures of the day of judgment. In contrast, those clothed in Christ's righteousness are clothed not with sackcloth and shame but with 'fine linen, bright and clean' (Rev 19:8). The garment-change from sackcloth to fine linen is the gospel in miniature: judgment-clothing exchanged for righteousness-clothing through the work of Christ.</p>",
    "19": "<p>'They will throw their silver into the streets, and their gold will be treated as an unclean thing. Their silver and gold will not be able to save them in the day of the LORD's wrath' — the absolute inefficacy of wealth in the day of judgment. Peter echoes this precisely: 'you were redeemed... not with perishable things such as silver or gold, but with the precious blood of Christ' (1 Pet 1:18-19). What the merchants' gold cannot buy, the blood of the Son of God freely provides.</p>",
    "20": "<p>'They took pride in their beautiful jewelry and used it to make their detestable idols and vile images; therefore I will turn their jewelry into an unclean thing' — the conversion of beauty into defilement through idolatry. The reversal of beauty into defilement is the judgment on misplaced devotion. Christ restores beauty to its proper end: the beautiful things of creation point to the Creator rather than replacing him. 'Whether you eat or drink, or whatever you do, do all to the glory of God' (1 Cor 10:31).</p>",
    "21": "<p>'I will give their wealth as plunder to foreigners and as loot to the wicked of the earth, and they will desecrate it' — the wealth given to those who will desecrate it rather than to those who would honor YHWH with it. Jesus's parables warn against the same fate: the rich man whose abundance profits nothing (Luke 12:16-21); the talents given to others when the unfaithful servant forfeits them (Matt 25:28-29). Wealth entrusted to the unbelieving community ultimately transfers to others.</p>",
    "22": "<p>'I will turn my face away from them, so they will desecrate my treasured place; robbers will enter it and desecrate it' — the divine face-turning makes the sanctuary vulnerable. Jesus's death produces the reverse: the face of God is turned toward humanity in the cross (2 Cor 5:19: God was reconciling the world to himself in Christ). The desecrated sanctuary of 586 BCE is answered by the new sanctuary — Christ's body — that cannot be finally desecrated (John 2:19-22; Rev 21:22).</p>",
    "23": "<p>'Prepare chains! For the land is full of bloodshed, and the city is full of violence' — the chains of exile. The NT inverts the chain imagery: Paul is 'an ambassador in chains' (Eph 6:20), bound not by divine judgment but by his identification with Christ's imprisonment. The chains that judgment imposes become, in the NT, the chains that the gospel's servants willingly wear in solidarity with the imprisoned Messiah.</p>",
    "24": "<p>'I will bring the worst of the nations to take possession of their houses; I will put an end to the pride of the mighty, and their sanctuaries will be desecrated' — the end of the 'pride of the mighty' (<em>gaon azim</em>) through the most ruthless of nations. The same dismantling of human pride characterizes the way of the cross: 'God chose the weak things of the world to shame the strong' (1 Cor 1:27). The cross is the ultimate anti-monument to human pride.</p>",
    "25": "<p>'When anguish comes, they will seek peace, but there will be none' — the peace that cannot be found at the last hour. Christ offers the peace that the world cannot give (John 14:27) — but it is a peace that must be received before the day of anguish, not sought in it. The urgency of the gospel is precisely this: peace with God is available now through Christ (Rom 5:1), but the window is not unlimited.</p>",
    "26": "<p>'Calamity upon calamity will come, and rumor upon rumor. They will seek a vision from the prophet, but teaching will fail the priest and counsel the elders' — the complete failure of every source of spiritual guidance in the crisis. Jesus stands as the fulfillment of all three: prophet, priest, and king (Heb 1:1-3; 7:26; Rev 19:16). When the systems that Israel trusted fail simultaneously, the one who combines all three offices becomes the only source of vision, teaching, and counsel.</p>",
    "27": "<p>'The king will mourn, the prince will be clothed with despair, and the hands of the people of the land will tremble with fear. I will deal with them according to their own conduct, and by their own standards I will judge them. Then they will know that I am the LORD' — the comprehensive despair of the leadership. The kings of the earth hide in caves and call for mountains to fall on them in Revelation 6:15-17, despairing before the wrath of the Lamb. The final knowledge of YHWH that judgment produces is here the recognition that the one who judges is the same one who offered salvation through the Lamb.</p>"
  },
  "8": {
    "1": "<p>Date: sixth year, sixth month, fifth day (592 BCE). Ezekiel is sitting with the elders of Judah — the exilic leadership consulting the prophet — when the vision begins. The hand of YHWH seizing the prophet while he is in a social setting (elders sitting with him) marks the involuntary nature of the prophetic experience. Christ's ministry similarly breaks into ordinary social settings — meals, synagogues, journeys — bringing the divine encounter into the mundane moment.</p>",
    "2": "<p>'I looked, and there was a figure that looked like a man. Downward from what looked like his waist was fire, and from his waist upward he looked like glowing metal, as bright as fire' — the same figure as in 1:27, now appearing in the temple vision. This figure of fire and glowing metal is the divine messenger who will guide Ezekiel through the temple. The resurrected Christ appears in similar terms in Rev 1:14-15 (eyes like a flame of fire, feet like burnished bronze, voice like many waters). The figure of judgment in Ezekiel 8 anticipates the figure of the risen Christ who walks among the seven lampstands.</p>",
    "3": "<p>'He stretched out what looked like a hand and took me by the hair of my head; the Spirit lifted me up between heaven and earth and brought me in visions of God to Jerusalem, to the north gate of the inner court, where the idol that provokes jealousy stood' — the Spirit's transportation of the prophet to the temple to see its corruption. Jesus, transported in his temptation to the 'pinnacle of the temple' (Matt 4:5), sees the same site of religious corruption that Ezekiel witnesses in vision. The 'idol that provokes to jealousy' (<em>semel haqin'ah</em>) set at the north gate of the inner court is exactly what the temple mount had become under Manasseh (2 Kgs 21:7).</p>",
    "4": "<p>'The glory of the God of Israel was there, like the vision I had seen in the valley' — the contrast at the heart of the vision: the glory of YHWH remains present in the temple even as the abominations accumulate around it. Before the glory departs (ch 10), it is still there, witnessing the defilement. Christ similarly remains present in the temple of Jerusalem, overturning tables and teaching (Matt 21:12-17), the divine presence refusing to leave without being heard.</p>",
    "5": "<p>'Son of man, look toward the north' — the first of four abominations, all located in different parts of the temple precinct. The systematic tour of the temple's four corruption sites prefigures Jesus's comprehensive indictment of the temple establishment in Matt 23 (woes against scribes and Pharisees) and his announcement of the temple's destruction (Matt 24:2). Both the prophet's vision-tour and the Messiah's physical tour arrive at the same verdict: the house has become desolate (Matt 23:38).</p>",
    "6": "<p>'Son of man, do you see what they are doing — the utterly detestable practices the house of Israel is committing here, that will drive me far from my sanctuary?' — the abominations driving YHWH away. The divine presence is not compelled to remain where it is dishonored. The same logic governs the departure of the Holy Spirit's influence from a community that grieves him (Eph 4:30; 1 Thess 5:19). The exile of the glory precedes the exile of the people; the Spirit's withdrawal precedes spiritual death.</p>",
    "7": "<p>'He brought me to the entrance of the court, and I looked and saw a hole in the wall' — the hidden entrance to the inner corruption. The hole in the wall that Ezekiel digs through at God's command reveals what is being done in secret. Jesus applies the same principle: 'there is nothing hidden that will not be disclosed, and nothing concealed that will not be known or brought out into the open' (Luke 8:17). The secret idolatry of Ezekiel's temple points to the judgment-day disclosure of all hidden things.</p>",
    "8": "<p>'Son of man, dig into the wall' — Ezekiel is commanded to be the agent of discovery, digging through to see the hidden corruption. The act anticipates the gospel's role as the revealer of what has been concealed — Christ as the one who brings hidden things to light (1 Cor 4:5; Eph 5:13). The digging through the wall is the action that prepares the vision: revelation requires the removal of the obscuring surface.</p>",
    "9": "<p>'Go in and see the wicked and detestable things they are doing here' — YHWH's invitation to see the full reality of the sin that provokes judgment. The divine willingness to show his prophet the full extent of the corruption corresponds to the NT's unflinching diagnosis of sin: 'all have sinned and fall short of the glory of God' (Rom 3:23). The vision of sin's full extent is necessary for the appreciation of grace's full sufficiency.</p>",
    "10": "<p>'I went in and looked, and I saw portrayed all over the walls all kinds of crawling things and unclean animals and all the idols of Israel' — the walls covered with images of unclean animals and idols. The contrast with the cherubim-and-palm decorative program of Ezekiel's ideal temple (41:18-19) is total. Where the true temple will be covered with images of divine messengers and life-giving trees, the corrupted temple is covered with images of unclean animals and false gods. The decorative program reveals the theological program.</p>",
    "11": "<p>'Seventy of the elders of Israel were standing there, with Jaazaniah son of Shaphan standing among them. Each had a censer in his hand, and the fragrant incense cloud was rising' — seventy elders (the number of the Sanhedrin, the full representative body of Israel) officiating at the illicit worship. The incense rising to the images is the most blatant possible appropriation of the worship that belongs to YHWH. The number seventy and the censer-wielding echoes Num 11:16-25 (the seventy elders who received the Spirit); the spiritual leadership has exchanged Spirit-empowered service for idolatrous imitation.</p>",
    "12": "<p>'Son of man, have you seen what the elders of Israel are doing in the darkness, each in his chamber of images? They say, The LORD does not see us; the LORD has forsaken the land' — the theology that enables secret sin: 'the LORD does not see.' Jesus addresses this directly in the parable of the wicked servants (Luke 12:45: 'my master is delayed') — the belief that divine absence enables sin. Paul's response: 'Nothing in all creation is hidden from God's sight' (Heb 4:13). The One who sees in secret rewards in secret and also judges in secret.</p>",
    "13": "<p>'You will see them doing things that are even more detestable' — the escalating tour of corruption: each abomination worse than the last. The progression of spiritual decline has no natural floor — without the intervention of grace, corruption deepens. The gospel interrupts the escalation: 'where sin increased, grace increased all the more' (Rom 5:20). The downward spiral of Ezekiel's temple tour is answered by the upward spiral of Romans 5-8.</p>",
    "14": "<p>'He brought me to the entrance of the north gate of the LORD's house, and I saw women sitting there, weeping for Tammuz' — women weeping for the Babylonian vegetation deity Tammuz (<em>Dumuzi</em>), whose annual death and descent to the underworld was mourned in a major Babylonian religious festival. The women's tears for Tammuz — a deity whose death and (possible) resurrection was the center of a pagan cult — stand in ironic contrast with the tears that belong to Christ's death: 'Do not weep for me; weep for yourselves and for your children' (Luke 23:28). The tears of the women at the cross (Luke 23:27) are the true fulfillment of the tears that pagan religion misdirected toward Tammuz.</p>",
    "15": "<p>'Do you see this? You will see things even more detestable than these' — the repeated escalation formula. The progressive revelation of greater and greater corruption prefigures the process of conviction by the Holy Spirit (John 16:8-11) — the Spirit who brings the full extent of sin to light before the full extent of grace can be received. YHWH showing Ezekiel things 'even more detestable' is the uncomfortable work of thorough conviction.</p>",
    "16": "<p>'He brought me into the inner court of the LORD's house, and there at the entrance to the temple, between the porch and the altar, were about twenty-five men. With their backs toward the temple of the LORD and their faces toward the east, they were bowing down to the sun in the east' — the most egregious abomination: the priests facing away from the Holy of Holies to worship the sun. The posture — backs to YHWH, faces to the sun-god — is the visual expression of apostasy. Christ calls for the reversal: 'turn from darkness to light' (Acts 26:18). The men facing east to worship the creation are the type of those who 'exchanged the truth about God for a lie and worshiped and served created things rather than the Creator' (Rom 1:25).</p>",
    "17": "<p>'Have you seen this, son of man? Is it a trivial matter for the house of Judah to do the detestable things they are doing here? Must they also fill the land with violence and continually provoke me to anger? Look at them putting the branch to their nose!' — the 'branch to the nose' (<em>sholeychim et-hazmorah el-appam</em>) is an obscure gesture, possibly a pagan ritual act of contempt or an idolatrous practice. The connection between idolatry and violence is consistent throughout the prophets: false worship of other gods produces social violence and injustice. Christ's reversal addresses both simultaneously — 'love the Lord your God' (the vertical) and 'love your neighbor as yourself' (the horizontal) as the two commandments on which everything hangs (Matt 22:37-40).</p>",
    "18": "<p>'Therefore I will act in wrath; my eye will not spare them, nor will I have pity. Although they shout in my ears, I will not listen to them' — the divine refusal to hear prayer from those who continue in willful idolatry. Psalm 66:18 states the same principle: 'if I had cherished sin in my heart, the Lord would not have listened.' Christ makes the same demand: the one who hears his words and does not do them is like the foolish builder (Matt 7:26-27). Yet even in this 'will not listen,' Christ has become the mediator who makes prayer effective: the one prayer YHWH always hears is the cry of the one in Christ (Heb 7:25; Rom 8:34).</p>"
  },
  "9": {
    "1": "<p>'He called in my hearing with a loud voice: Bring forward those who carry out punishment against the city, each man with his destroying weapon in his hand' — the six judgment-executors summoned. The loud voice calling the executors is the same calling that will send the angels at the eschaton: 'He will send his angels with a loud trumpet call, and they will gather his elect from the four winds' (Matt 24:31). The angels of judgment in Ezekiel 9 are the type of the eschatological harvesters of Matthew 13:39-42.</p>",
    "2": "<p>'Six men came from the direction of the upper gate, which faces north, each with his deadly weapon in his hand; and with them was a man clothed in linen, with a writing kit at his side' — the man in linen with a writing kit among the six executors. The man in linen stands apart from the destroyers — he is a scribe, a sealer, not an executioner. This figure of the divine scribe who marks the faithful for preservation before the executors advance anticipates the sealing of the 144,000 before the angels of judgment are released (Rev 7:1-3).</p>",
    "3": "<p>'Now the glory of the God of Israel had gone up from above the cherubim, where it had been, and moved to the threshold of the temple. Then the LORD called to the man clothed in linen who had the writing kit at his side' — the glory moving to the threshold is the first stage of the departure (ch 10 will record the full departure). Before the judgment begins, the glory repositions — a divine withdrawal that makes the judgment possible and signals its authority. The command to the man in linen comes directly from the glory at the threshold.</p>",
    "4": "<p>'Go throughout the city of Jerusalem and put a mark on the foreheads of those who grieve and lament over all the detestable things that are done in it' — the tav-mark on the foreheads of the faithful remnant. The mark identifies those who mourn over sin while surrounded by it — the community of conscience within a corrupt society. This mark is directly echoed in: the seal of the Holy Spirit (2 Cor 1:22; Eph 1:13-14; 4:30), the sealing of the 144,000 (Rev 7:3), the name of God on the foreheads of the redeemed (Rev 14:1; 22:4). The seal that preserves in judgment is the Spirit of Christ, given to those who belong to him.</p>",
    "5": "<p>'As I listened, he said to the others: Go throughout the city after him and kill, without showing pity or compassion' — the executors follow the scribe: the judgment comes only after the sealing. This sequence — marking the faithful first, then judgment — is the consistent pattern of divine judgment throughout Scripture: Passover blood on the doorposts before the angel of death passes through; Noah sealed in the ark before the flood; Rahab's scarlet thread before Jericho's fall. Christ's death is the ultimate prior sealing before eschatological judgment.</p>",
    "6": "<p>'Slaughter old men, young men and maidens, women and children, but do not touch anyone who has the mark' — the comprehensive scope of judgment contrasted with the absolute protection of the marked. 'Begin at my sanctuary' — judgment starting at the house of God. Peter quotes this directly: 'For it is time for judgment to begin with the household of God; and if it begins with us, what will be the outcome for those who do not obey the gospel of God?' (1 Pet 4:17). The sanctuary-first judgment is the pattern for the church's experience of discipline before the world faces judgment.</p>",
    "7": "<p>'Defile the temple and fill the courts with the slain. Go!' — the defilement of the temple by the slain — corpses rendering the sacred space impure. The deaths that defile the temple are the consequence of the idolatry that had already spiritually defiled it (ch 8). Jesus's prediction of the temple's physical destruction (Matt 24:2) is the final form of this judgment: the physically destroyed temple as the terminus of the spiritually destroyed temple. The new temple is Christ's body, which cannot be defiled by death because death cannot hold it (Acts 2:24).</p>",
    "8": "<p>'While they were killing and I was left alone, I fell facedown, crying out: Alas, Sovereign LORD! Are you going to destroy the entire remnant of Israel in this outpouring of your wrath on Jerusalem?' — Ezekiel's intercession on behalf of Israel during the judgment vision. The prophet prostrate before YHWH, crying out for the remnant, is the OT type of Christ's high-priestly intercession: 'He always lives to intercede for them' (Heb 7:25). The one who has seen the full extent of the judgment becomes the intercessor who cries for the remnant.</p>",
    "9": "<p>'He answered me: The sin of Israel and Judah is exceedingly great; the land is full of bloodshed and the city is full of injustice. They say, The LORD has forsaken the land; the LORD does not see' — the divine confirmation of the full extent of the sin that Ezekiel witnessed in the temple tour. The 'LORD has forsaken/does not see' is the precise theology that enabled the sin: conviction of divine absence enabling human autonomy. The cross answers this directly: it is the place where God appeared most absent ('My God, my God, why have you forsaken me?' — Matt 27:46) and most present (2 Cor 5:19: God was in Christ reconciling the world).</p>",
    "10": "<p>'So I will not look on them with pity or spare them, but I will bring down on their own heads what they have done' — the principle of exact recompense. Christ absorbs the exact recompense that would have fallen on sinners: 'Christ redeemed us from the curse of the law by becoming a curse for us' (Gal 3:13). The 'bringing down on their own heads what they have done' is precisely what did not happen to the believer because it happened at the cross.</p>",
    "11": "<p>'Then the man in linen with the writing kit came back and reported, I have done as you commanded' — the scribe's return report after completing the marking. The mission accomplished. The completeness of the sealing before judgment began means not one who should have been sealed was missed. In Christ, the seal of the Spirit is equally comprehensive: 'Having believed, you were marked in him with a seal, the promised Holy Spirit' (Eph 1:13). The divine scribe misses no one who belongs to him.</p>"
  },
  "10": {
    "1": "<p>'I looked, and I saw in the expanse above the heads of the cherubim something like a throne of lapis lazuli appearing above them' — the chariot-throne vision in the temple context. The lapis lazuli (sapphire) throne of 1:26 reappears, now situated above the cherubim in the temple rather than above the Chebar canal. The same throne of judgment and glory that appeared at Ezekiel's commission now appears at Jerusalem for the departure of the glory. The divine throne's mobility — appearing at the river and at the temple — anticipates the NT's insistence that the divine presence is not confined to sacred geography (John 4:21-24).</p>",
    "2": "<p>'He said to the man clothed in linen: Go in among the wheels beneath the cherubim; fill your hands with burning coals from among the cherubim and scatter them over the city' — the divine scribe who marked the faithful (ch 9) now becomes the agent of judgment-fire over the city. The coals from the divine chariot-throne scattered over Jerusalem recall the altar coal placed on Isaiah's lips for cleansing (Isa 6:6-7). Fire from the divine presence is both purifying and consuming: the same fire that cleanses the lips of the prophet consumes the city that refused cleansing.</p>",
    "3": "<p>'The cherubim were standing on the south side of the temple when the man went in, and a cloud filled the inner court' — the cloud of divine glory filling the inner court as the glory prepares to depart. The cloud of YHWH's presence (the Shekinah) filling the space is simultaneously the most intense manifestation of divine presence and the precursor to the most significant departure. The cloud that filled Solomon's temple at dedication (1 Kgs 8:10-11) now fills the temple one last time before leaving.</p>",
    "4": "<p>'Then the glory of the LORD rose from above the cherubim and moved to the threshold of the temple. The cloud filled the temple, and the court was full of the radiance of the LORD's glory' — the first stage of the glory's departure: from above the cherubim to the threshold. The radiance (<em>nogah</em>, H5051) filling the court — the surrounding brightness of the divine presence — is the same radiance that will mark the New Jerusalem: 'the city does not need the sun or the moon to shine on it, for the glory of God gives it light' (Rev 21:23).</p>",
    "5": "<p>'The sound of the wings of the cherubim could be heard as far away as the outer court, like the voice of God Almighty when he speaks' — the thunderous sound of the departing glory. The comparison to 'the voice of God Almighty' (<em>qol El Shaddai</em>) invokes the divine name of patriarchal revelation (Exod 6:3; Gen 17:1). The sound accompanying the glory's departure is the same voice that spoke to the patriarchs — YHWH's presence withdrawing while his voice is still heard.</p>",
    "6": "<p>'When the LORD commanded the man clothed in linen: Take fire from among the wheels, from among the cherubim, the man went in and stood beside a wheel' — the man in linen standing beside the wheel to take the judgment-coals. The wheels of the divine chariot carry the fire of divine judgment — the same wheels that appeared in ch 1 as the moving spirit of the chariot. The fire taken from the wheels is fire with the full authority of the divine throne behind it.</p>",
    "7": "<p>'Then one of the cherubim reached out his hand to the fire that was among them. He took some of it and put it into the hands of the man in linen, who took it and went out' — the cherub placing the fire in the human hands of the linen-clad figure. The divine fire mediated through angelic hands to human hands — the chain of divine authority. Christ as the mediator of divine fire: 'I have come to bring fire on the earth, and how I wish it were already kindled!' (Luke 12:49). The fire of the Spirit poured out at Pentecost (Acts 2:3: tongues as of fire) comes through the mediation of the risen and ascended Christ.</p>",
    "8": "<p>'Under the wings of the cherubim could be seen what appeared to be human hands' — the hands of the cherubim: the divine chariot has human-form elements alongside the animal-form elements. The divine chariot bears the marks of humanity (hands) as well as the signs of transcendence (wings, wheels, fire). Christ, fully human and fully divine, embodies permanently what the chariot-vision displays symbolically.</p>",
    "9": "<p>'I looked and saw four wheels beside the cherubim, one beside each cherub; the wheels sparkled like topaz' — the topaz wheels of the divine chariot. Topaz (<em>tarshish</em>, H8658, a precious stone) sparkle: the divine mobility is precious, beautiful, and aligned with the throne's glory. The wheels of the chariot moving in four directions simultaneously represent the omnipresence of the divine sovereignty — no direction is closed to YHWH's movement.</p>",
    "10": "<p>'As for their appearance, the four of them looked alike; each was like a wheel intersecting a wheel' — the wheel-within-wheel construction representing movement in any direction without turning. The divine chariot can move instantly in any direction — the representation of divine omnipresence and sovereign freedom. Christ's resurrection body moves with the same freedom: appearing through locked doors (John 20:19), ascending and sitting at the right hand (Acts 1:9-10; Heb 1:3), coming again in glory (Matt 24:30).</p>",
    "11": "<p>'As they moved, they would go in any one of the four directions the cherubim faced; the wheels did not turn about as the cherubim went, for the cherubim could go in whichever direction they chose without the wheels turning' — the coordinated movement of cherubim and wheels: perfect unity of will and motion. The divine chariot-throne is a picture of perfect unity between the divine will and its execution. Christ as the one in whom divine will is perfectly executed: 'I have come down from heaven not to do my will but to do the will of him who sent me' (John 6:38).</p>",
    "12": "<p>'Their entire bodies, including their backs, their hands, and their wings, were completely full of eyes, as were their four wheels' — the all-seeing eyes covering the bodies and wheels of the divine chariot: nothing escapes the divine gaze. Revelation 4:6 describes the four living creatures around the throne as 'covered with eyes, in front and in back' — the same total-vision characteristic. Christ as the one 'to whom all are naked and exposed' (Heb 4:13) embodies the all-seeing divine gaze that the chariot-throne displays.</p>",
    "13": "<p>'I heard the wheels being called the whirling wheels — these were the terms I heard' — the naming of the wheels: <em>galgal</em> (H1534, wheel/whirling) for the wheels of the chariot that move with supernatural speed. The whirling quality of the divine chariot's wheels represents the speed of divine action — YHWH moves with absolute swiftness when the moment for action arrives. Contrast the 'slowness' that false prophets attributed to divine action (12:22-28): the whirling wheels refute the 'the days drag on' proverb.</p>",
    "14": "<p>'Each of the cherubim had four faces: the first face was a cherub's face, the second was a human face, the third the face of a lion, and the fourth the face of an eagle' — the four-faced cherubim. In ch 1 the four faces were: lion, ox, human, eagle (1:10). Here the ox-face is replaced by a cherub-face. The four faces correspond closely to the four living creatures of Revelation 4:7: lion, ox/calf, human, eagle — the faces that traditional Christian interpretation connects to the four gospel writers (Matthew/human, Mark/lion, Luke/ox, John/eagle). The divine chariot's faces become the faces of the four gospel testimonies to Christ.</p>",
    "15": "<p>'The cherubim rose upward — these were the living creatures I had seen by the Chebar River' — the explicit identification of the temple-vision cherubim with the Chebar-canal living creatures. The same divine chariot-throne that appeared in Babylonian exile returns to Jerusalem for the glory's departure. The theological implication: YHWH's chariot-throne moves freely between Jerusalem and Babylon, between the sacred center and the place of exile. Christ, present with his disciples in Galilee, Jerusalem, Emmaus, and the seashore after the resurrection, embodies this same freedom.</p>",
    "16": "<p>'When the cherubim moved, the wheels beside them moved; and when the cherubim spread their wings to rise from the ground, the wheels did not leave their side' — the perfect coordination of the cherubim and wheels: the created beings and the divine chariot's mechanical components move in perfect unity. The Spirit's coordination of the body of Christ (1 Cor 12:12-13) reflects this same principle: diverse members moving in unified response to the same divine will.</p>",
    "17": "<p>'When the cherubim stood still, they also stood still; and when the cherubim rose, they rose with them, for the spirit of the living creatures was in them' — 'the spirit of the living creatures was in them' (<em>ruach hachayyah bahem</em>): the animating Spirit within the wheels. The divine chariot moves because the Spirit animates it from within. Paul applies the same interior-Spirit logic to believers: 'If the Spirit of him who raised Jesus from the dead is living in you, he who raised Christ from the dead will also give life to your mortal bodies because of his Spirit who lives in you' (Rom 8:11).</p>",
    "18": "<p>'Then the glory of the LORD departed from over the threshold of the temple and stopped above the cherubim' — the glory leaving the threshold (where it paused in v.4) and returning above the cherubim. The departure is progressive, intentional, and painful. Christ's departure from Jerusalem follows the same pattern: the gradual withdrawal (growing opposition, rejected warnings) culminating in the lamentation 'your house is left to you desolate' (Matt 23:38). The glory that departs will return.</p>",
    "19": "<p>'While I watched, the cherubim spread their wings and rose from the ground, and as they went, the wheels went with them. They stopped at the entrance of the east gate of the LORD's house, and the glory of the God of Israel was above them' — the cherubim at the east gate with the glory above them: the final position within the temple precinct before the full departure (11:22-23) to the Mount of Olives. The east gate that is 'shut' in 44:1-2 after the glory returns is the same gate from which the glory departed. Christ's ascension from the Mount of Olives (Acts 1:9-12) and his predicted return 'in the same way' (Acts 1:11) from the east fulfills this departure pattern.</p>",
    "20": "<p>'These were the living creatures I had seen beneath the God of Israel by the River Chebar, and I knew they were cherubim' — the explicit identification complete: the river-creatures = the temple-creatures = cherubim. The consistency of the divine chariot across two visions (Chebar and Jerusalem) and across the entire arc of the book (exile → judgment → restoration) demonstrates that the same God who appears in Babylon appears in Jerusalem and will appear in the new temple. 'Jesus Christ is the same yesterday and today and forever' (Heb 13:8).</p>",
    "21": "<p>'Each had four faces and four wings, and under their wings was what looked like human hands' — the summary description of the cherubim: four faces (divine, human, animal, celestial), four wings (covering, moving, honoring), and human hands (acting, receiving, serving). The divine chariot bears the permanent marks of both transcendence and humanness — anticipating the Incarnation in which the transcendent takes on the human permanently.</p>",
    "22": "<p>'Their faces had the same appearance as those I had seen by the Chebar River — each went straight ahead' — the final note of consistency and directness: 'each went straight ahead' (<em>el ever penehem yelekhu</em>). The straight-ahead movement of the divine chariot, without deviation or turning back, points to the intentionality of YHWH's purposes. The mission of the Son was similarly without deviation: 'he steadfastly set his face to go to Jerusalem' (Luke 9:51). The chariot that departs from the temple goes straight — and it will return straight, from the same direction (43:1-2).</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'ezekiel')
    merge_comm(existing, EZK_CHRIST)
    save_comm('mkt-christ', 'ezekiel', existing)

    out = json.loads((ROOT / 'data/commentary/mkt-christ/ezekiel.json').read_text())
    il  = json.loads((ROOT / 'data/interlinear/ezekiel.json').read_text())

    all_ok = True
    for ch in [6, 7, 8, 9, 10]:
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(out.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out.get(ck, {}))} verses)')
    if all_ok:
        print('All verses present')

if __name__ == '__main__':
    main()
